def apply(state, ctx):
    counts = {}
    for picks in ctx['interactions']['votes'].values():
        for pid in picks:
            counts[pid] = counts.get(pid, 0) + 1
    best = max(counts.values())
    for pid, count in counts.items():
        if count == best:
            state.add_points('id:' + pid, 3)

